<script>
(function(){
  if(window.lucide) lucide.createIcons();

  const tabDocumento = document.getElementById('tabDocumento');
  const tabGrafico = document.getElementById('tabGrafico');
  const panelDocumento = document.getElementById('panelDocumento');
  const panelGrafico = document.getElementById('panelGrafico');
  const graphicTools = document.getElementById('graphicTools');

  function showDocumento(){
    tabDocumento.classList.add('bg-[#0F172A]', 'text-slate-100', 'border-t-2', 'border-t-orange-500');
    tabDocumento.classList.remove('bg-slate-800/50', 'text-slate-400');
    tabGrafico.classList.remove('bg-[#0F172A]', 'text-slate-100', 'border-t-2', 'border-t-purple-500');
    tabGrafico.classList.add('bg-slate-800/50', 'text-slate-400');
    panelDocumento.classList.remove('hidden');
    panelGrafico.classList.add('hidden');
    graphicTools.classList.add('hidden');
  }

  function showGrafico(){
    tabGrafico.classList.add('bg-[#0F172A]', 'text-slate-100', 'border-t-2', 'border-t-purple-500');
    tabGrafico.classList.remove('bg-slate-800/50', 'text-slate-400');
    tabDocumento.classList.remove('bg-[#0F172A]', 'text-slate-100', 'border-t-2', 'border-t-orange-500');
    tabDocumento.classList.add('bg-slate-800/50', 'text-slate-400');
    panelDocumento.classList.add('hidden');
    panelGrafico.classList.remove('hidden');
    graphicTools.classList.remove('hidden');
  }

  tabDocumento.addEventListener('click', showDocumento);
  tabGrafico.addEventListener('click', (e) => {
    if(!e.target.closest('.close-tab')) showGrafico();
  });

  document.querySelector('.close-tab').addEventListener('click', (e) => {
    e.stopPropagation();
    showDocumento();
  });

  // Tool selection
  const tools = document.querySelectorAll('.tool-btn');
  tools.forEach(btn => {
    btn.addEventListener('click', () => {
      tools.forEach(t => {
        t.classList.remove('active', 'text-slate-300');
        t.classList.add('text-slate-400');
      });
      btn.classList.add('active', 'text-slate-300');
      btn.classList.remove('text-slate-400');
    });
  });

  // Node selection
  const nodes = document.querySelectorAll('.ex-node');
  nodes.forEach(node => {
    node.addEventListener('click', () => {
      nodes.forEach(n => n.classList.remove('ring-2', 'ring-blue-400'));
      node.classList.add('ring-2', 'ring-blue-400');
    });
  });

  // Save button
  const guardar = document.getElementById('btnGuardar');
  if(guardar){
    guardar.addEventListener('click', () => {
      const original = guardar.innerHTML;
      guardar.innerHTML = '<i data-lucide="check" class="w-3.5 h-3.5"></i><span>Guardado</span>';
      guardar.classList.replace('bg-blue-600','bg-green-600');
      guardar.classList.replace('hover:bg-blue-500','hover:bg-green-500');
      if(window.lucide) lucide.createIcons();
      setTimeout(() => {
        guardar.innerHTML = original;
        guardar.classList.replace('bg-green-600','bg-blue-600');
        guardar.classList.replace('hover:bg-green-500','hover:bg-blue-500');
        if(window.lucide) lucide.createIcons();
      }, 1500);
    });
  }
})();
</script>
